:root {
  --card-bg: #ffffff;
  --card-border: #e2e0f0;
  --header-bg: #4c3d8f;
  --header-text: #ffffff;
  --meta-text: #c5bef0;
  --badge-bg: #f04a4a;
  --badge-text: #ffffff;
  --leader-bg: #f4f1ff;
  --leader-border: #c9bff5;
  --row-border: #f0eef9;
  --rank-color: #9b8ec4;
  --name-color: #2d2550;
  --score-color: #4c3d8f;
  --bar-track: #ede9fa;
  --bar-leader: #4c3d8f;
  --bar-default: #a899e6;
  --delta-up: #22a06b;
  --delta-down: #e0443c;
  --delta-neutral: #9b8ec4;
  --footer-bg: #f9f8ff;
  --chip-border: #e2e0f0;
  --stat-label-color: #9b8ec4;
  --stat-value-color: #2d2550;
}

.scorecard {
  width: 500px;
  background: var(--card-bg);
  border: 1.5px solid var(--card-border);
  border-radius: 16px;
  overflow: hidden;
  margin: 0 auto;
}

.scorecard-header {
  background: var(--header-bg);
  padding: 14px 18px;
  display: flex;
  align-items: center;
  gap: 12px;
}

.game-icon {
  font-size: 28px;
  line-height: 1;
}

.header-text {
  flex: 1;
}

.game-title {
  font-size: 17px;
  font-weight: 700;
  color: var(--header-text);
  margin: 0;
  line-height: 1.2;
}

.game-meta {
  font-size: 12px;
  color: var(--meta-text);
  margin: 2px 0 0 0;
  line-height: 1;
}

.round-badge {
  background: var(--badge-bg);
  color: var(--badge-text);
  font-size: 11px;
  font-weight: 700;
  padding: 4px 10px;
  border-radius: 20px;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.players-grid {
  padding: 10px 16px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.player-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 10px;
  border-radius: 10px;
  border: 1.5px solid var(--row-border);
}

.player-leader {
  background: var(--leader-bg);
  border-color: var(--leader-border);
}

.player-rank {
  font-size: 12px;
  font-weight: 700;
  color: var(--rank-color);
  width: 14px;
  text-align: center;
}

.player-avatar {
  font-size: 18px;
  line-height: 1;
}

.player-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--name-color);
  width: 52px;
}

.score-bar-wrap {
  flex: 1;
  height: 8px;
  background: var(--bar-track);
  border-radius: 99px;
  overflow: hidden;
}

.player-leader .score-bar {
  height: 100%;
  background: var(--bar-leader);
  border-radius: 99px;
}

.score-bar {
  height: 100%;
  background: var(--bar-default);
  border-radius: 99px;
}

.player-score {
  font-size: 16px;
  font-weight: 700;
  color: var(--score-color);
  width: 24px;
  text-align: right;
}

.player-delta {
  font-size: 11px;
  font-weight: 700;
  width: 24px;
  text-align: right;
}

.delta-up {
  color: var(--delta-up);
}

.delta-down {
  color: var(--delta-down);
}

.delta-neutral {
  color: var(--delta-neutral);
}

.scorecard-footer {
  background: var(--footer-bg);
  border-top: 1.5px solid var(--card-border);
  padding: 10px 16px;
  display: flex;
  gap: 8px;
}

.stat-chip {
  flex: 1;
  border: 1.5px solid var(--chip-border);
  border-radius: 10px;
  padding: 7px 10px;
  display: flex;
  flex-direction: column;
  gap: 3px;
  background: var(--card-bg);
}

.stat-label {
  font-size: 10px;
  font-weight: 600;
  color: var(--stat-label-color);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.stat-value {
  font-size: 13px;
  font-weight: 700;
  color: var(--stat-value-color);
}
